public class HighestSharedDivisor {

    public static int gcd(int a, int b) {
        // Base case: if b is zero, a is the GCD
        if (b == 0) {
            return a;
        }
        // Recursive step: compute GCD of b and a % b
        return gcd(b, a % b);
    }

